<template>
    <div class="historyListContainier">
        <div class="backBtn" v-on:click="goBack">
            <img class="backBg" src="../assets/intersect.png" />
            <img class="back" src="../assets/backImg.png" />
        </div>
        <div class="content" v-if="!loading">
            <div class="title">版本历史记录</div>
            <HistoryView v-for="result in historyVersionInfo.data" v-bind:key="result.id" v-bind:info="result">
            </HistoryView>
        </div>
        <div v-if="loading">loading</div>
    </div>
</template>

<script>
import axios from 'axios'
import HistoryView from '@/components/HistoryView.vue'

export default {
    name: 'HistoryListView',
    computed: {
        info() {
            return this.$route.params.appInfo
        },
    },
    components: {
        HistoryView
    },
    data() {
        return {
            error: null,
            loading: false,
            historyVersionInfo: null
        }
    },
    watch: {
        // call again the method if the route changes
        '$route': 'fetchData'

    },
    created() {

        this.fetchData()
    },
    methods: {
        fetchData() {
            this.error = this.post = null
            this.loading = true
            axios.get('/appstore/api/v1/appstore/appVersion/history/' + this.$route.params.appInfo.id)
                .then(response => {
                    this.historyVersionInfo = response.data
                    this.loading = false
                })
                .catch(error => console.log(error))
        },
        goBack() {
            window.history.length > 1 ? this.$router.go(-1) : this.$router.push('/')
        }
    }
}
</script>

