<template>
    <div class="app_item">
        <img v-bind:src="info.logoSmall" v-on:click.self="navToDetail" />
        <div class="app_item_rightview">
            <div class="app_item_name" v-on:click.self="navToDetail">
                {{info.briefIntroduction}}
            </div>
            <div class="app_item_description" v-on:click.self="navToDetail">
                {{info.introduction}}
            </div>
            <DownloadView v-bind:info="info" />
        </div>
    </div>
</template>

<script>
import DownloadView from '@/components/DownloadView.vue'
import store from '../store/store'

export default {
    name: "AppViewItem",
    props: {
        info: Object
    },
    components: {
        DownloadView
    },
    data() {
        return {
            store: store
        }
    },
    methods: {
        navToDetail: function() {
            this.store.setSelectCurrentAppInfo(this.info)
            this.$router.push({
                name: 'appDetail'
            }) // -> /appDetail
        }
    }
}
</script>

