<template>
    <div class="download_action">
        <button class="btn_download" v-if="!isInstalled && !isDownloading" type="button" v-on:click.self="downloadApp">获取</button>
        <button class="btn_download" v-if="isInstalled" type="button" v-on:click.self="launchApp">运行</button>
        <button clsas="btn_download" v-if="isNeedUpdate" type="button" v-on:click.self="downloadApp">更新</button>
        <progress max="100" :value="downloadProgress" v-if="isDownloading"></progress>
    </div>
</template>

<script>
import dsBridge from "dsbridge"
import axios from 'axios'
import store from '../store/store'

export default {
    name: "DownloadView",
    props: {
        info: Object
    },
    data() {
        return {
            downloadProgress: null,
            isInstalled: false,
            isDownloading: false,
            downloadUrl: null,
            isNeedUpdate: false,
            store: store
        }
    },
    created() {
        console.log("refresh APK State-created")
        console.log("getInstalledState this.info.id :" + this.info.id)
        axios.get('/appstore/api/v1/appstore/appVersion/published/' + this.info.id)
            .then(response => {
                this.handleProgress(response.data)
            })
            .catch(error => {
                console.log("getInstalledState error" + error)
                this.handleProgress(this.store.mockedAppPublished)

            })
    },
    methods: {
        downloadApp: function() {
            axios.get('/appstore/api/v1/appstore/appVersion/published/' + this.info.id)
                .then(response => {
                    this.downloadUrl = response.data.data.downloadUrl
                    console.log("downloadUrl" + this.downloadUrl)
                    dsBridge.call("callProgress", this.downloadUrl, value => {
                        console.log(value)
                        if (value == 200) {
                            this.downloadProgress = 100
                            this.isInstalled = true
                            this.isDownloading = false
                            return
                        }
                        this.isDownloading = true
                        this.downloadProgress = value
                        console.log("progress:" + this.downloadProgress)
                    })
                })
                .catch(error => {
                    console.log(error)
                    this.downloadUrl = this.store.mockedAppPublished.data.downloadUrl
                    console.log("downloadUrl" + this.downloadUrl)
                    dsBridge.call("callProgress", this.downloadUrl, value => {
                        console.log(value)
                        if (value == 200) {
                            this.downloadProgress = 100
                            this.isInstalled = true
                            this.isDownloading = false
                            return
                        }
                        this.isDownloading = true
                        this.downloadProgress = value
                        console.log("progress:" + this.downloadProgress)
                    })
                })
        },
        launchApp: function() {
            console.log(this.downloadProgress + "downloadProgress--" +
                this.isInstalled + "isInstalled--" +
                this.downloadUrl + "downloadUrl--" +
                this.isDownloading + "isDownloading--")
            dsBridge.call("launchApk", this.downloadUrl);
        },
        fetchApkDownloadUrl: function() {
            axios.get('/appstore/api/v1/appstore/appVersion/published/' + this.info.id)
                .then(response => {
                    this.downloadUrl = response.data.data.downloadUrl
                })
                .catch(error => {
                    console.log(error)
                    this.downloadUrl = this.store.mockedAppPublished.downloadUrl
                })
        },
        getInstalledState(url, versionCode, packageName) {
            //check 
            return dsBridge.call("getAPKState", url + "," + versionCode + "," + packageName);
        },
        handleProgress: function(data) {
            this.downloadUrl = data.downloadUrl
            var state = this.getInstalledState(this.downloadUrl, data.versionCode, this.info.packageName)
            console.log("getInstalledState :" + state)
            if (state == "RUNNING") {
                console.log("getInstalledState :dsBridge.call(callProgress")
                dsBridge.call("callProgressDirectly", this.downloadUrl, value => {
                    console.log("getInstalledState: isDownloading = true")
                    this.isNeedUpdate = false
                    if (value == "200") {
                        this.downloadProgress = 100
                        this.isDownloading = false
                        this.isInstalled = true
                        return
                    }
                    this.isDownloading = true
                    this.downloadProgress = value
                    console.log("getInstalledState progress:" + this.downloadProgress)
                })
            } else if (state == "COMPLETED") {
                this.downloadProgress = 100
                this.isInstalled = true
                this.isDownloading = false
                this.isNeedUpdate = false
                console.log("getInstalledState == COMPLETED isInstalled:" + this.isInstalled)
            } else if (state == "UPDATE") {
                this.downloadProgress = 0
                this.isInstalled = false
                this.isDownloading = false
                this.isNeedUpdate = true
                console.log("getInstalledState == UPDATE isNeedUpdate:" + this.isNeedUpdate)
            } else {
                console.log("getInstalledState: unkown")
            }
        }
    }
}
</script>

