import Vue from 'vue'
import VueRouter from 'vue-router'
import Home from '../views/Home.vue'
import AppListView from '../components/AppListView.vue'
import AppDetailView from '../components/AppDetailView.vue'
import HistoryListView from '../components/HistoryListView.vue'
Vue.use(VueRouter)

const routes = [
  {
    path: '/',
    component: Home,
    children:[
      { path :'', component: AppListView ,
      },
      { path :'appDetail', 
        name :'appDetail', 
        component: AppDetailView,
    },
      { path :'historyListView', name:'historyListView',component: HistoryListView}
    ]
  },
  {
    path: '/about',
    name: 'About',
    // route level code-splitting
    // this generates a separate chunk (about.[hash].js) for this route
    // which is lazy-loaded when the route is visited.
    component: () => import(/* webpackChunkName: "about" */ '../views/About.vue')
  }
]

const router = new VueRouter({
  mode: 'history',
  base: process.env.BASE_URL,
  routes
})

export default router
