            <img class="back" src="../assets/backImg.png" />
        </div>
        <div class="content">
            <div class="app_item">
                <div class="img_container">
                    <img class="appIcon" v-bind:src="info.logoSmall" />
                </div>
    
                <div class="app_item_rightview">
                    <div class="app_item_name">
                        {{info.briefIntroduction}}
                    </div>
                    <div class="app_item_description">
