                    </div>
                    <DownloadView class="bt_download" v-bind:info="info" />
                </div>
            </div>
            <div class="divider" />
            <div class="publishInfo" v-if="!loading">
                <div class="publishInfoTitle">
                    <span class="title">新功能</span>
                    <span class="releaseVersion" v-on:click.self="goToHistoryList">版本{{publishedInfo.data.versionName}}</span>
                </div>
