            <div class="appPics">
                <div class="title">预览</div>
                <div class="appPics_content">
                    <img class="appPic" v-for="image in imgs" v-bind:key="image" :src="image" :alt="image" />
    
                </div>
            </div>
            <div class="divider" />
            <div class="font">
                <div class="title">
                    信息</div>
                <div class="font_info_content">
                    <div class="font_info_item">
                        <div class="info_item_value">
                            {{info.provider}}
                        </div>
                        <div class="info_item_name">
