                        </div>
                        <div class="info_item_name">
                            版权 </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>

<script>
import axios from 'axios'
import DownloadView from '@/components/DownloadView.vue'
import store from '../store/store'

export default {
    name: 'AppDetailView',
    computed: {
        info() {
            return this.store.state.currentAppInfo
        },
        size() {
            return this.formatBytes(this.publishedInfo.data.packageSize)
        },
        imgs() {
            return this.info.screenshots.split(",")
        }
    },
    components: {
        DownloadView
    },
    data() {
        return {
            error: null,
            loading: false,
            publishedInfo: null,
            id: null,
            store: store
        }
    },
    watch: {
        // call again the method if the route changes
        '$route': 'fetchData'
    },
    created() {
        this.fetchData()
    },
    methods: {
        fetchData() {

            this.error = this.post = null
            console.log(this.store.state)
            this.id = this.store.state.currentAppInfo.id
            this.loading = true
            axios.get('/appstore/api/v1/appstore/appVersion/published/' + this.id)
                .then(response => {
                    this.publishedInfo = response.data
                    this.loading = false
                })
                .catch(error => console.log(error))
        },
        goBack() {
            window.history.length > 1 ? this.$router.go(-1) : this.$router.push('/')
        },
        goToHistoryList() {
            this.$router.push({ name: 'historyListView', params: { appInfo: this.info } }) // -> /historyListView
        },
        formatBytes: function(a, b) {
            if (0 == a) return "0 Bytes";
            var c = 1024,
                d = b || 2,
                e = ["Bytes", "KB", "MB", "GB", "TB", "PB", "EB", "ZB", "YB"],
                f = Math.floor(Math.log(a) / Math.log(c));
            return parseFloat((a / Math.pow(c, f)).toFixed(d)) + " " + e[f]
        }
    }
}
</script>

