<template>
    <div class="border">
        <div class="title_bar">应用商店</div>
        <div class="container" v-if="!loading">
            <AppViewItem v-for="info in this.result.data.list" v-bind:key="info.id" v-bind:info="info">
            </AppViewItem>
        </div>
    </div>
</template>

<script>
import AppViewItem from '@/components/AppViewItem.vue'
import axios from 'axios'
import store from '../store/store'

export default {
    name: 'HelloWorld',
    props: {
        msg: String
    },
    components: {
        AppViewItem,
    },
    data() {
        return {
            loading: false,
            result: null,
            error: null,
            store: store
        }
    },
    created() {
        this.fetchData()
        console.log("created...")
    },
    methods: {
        fetchData: function() {
            this.loading = true
            axios
                .post('/appstore/api/v1/appstore/appInfo/search', {
                    page: '1',
                    pageSize: '10'
                })
                .then((response) => {
                    this.result = response.data
                    this.loading = false
                }).catch(() => {
                    this.result = this.store.mockedAppList
                    this.loading = false
                })
        }
    }
}
</script>

