<template>
    <div class="container">
        <div class="header">
            <span class="releaseVersion">{{info.versionName}}</span>
            <span class="releaseData">{{date}}</span>
        </div>
        <div class="content">{{info.releaseNotes}}
        </div>
        <div class="divider" />
    </div>
</template>

<script>
export default {
    name: 'HistoryView',
    computed: {
        date() {
            return this.dateFormatUtil(this.info.updated)
        }
    },
    props: {
        info: Object
    },
    data() {
        return {
            error: null,
            loading: false,
        }
    },
    methods: {
        dateFormatUtil: function(longTypeDate) {
            var dateTypeDate = "";
            var date = new Date();
            date.setTime(longTypeDate);
            dateTypeDate += date.getFullYear(); //年
            dateTypeDate += "-" + this.getMonth(date); //月 
            dateTypeDate += "-" + this.getDay(date); //日
            return dateTypeDate;
        },
        getMonth: function(date) {
            var month = "";
            month = date.getMonth() + 1;
            if (month < 10) {
                month = "0" + month;
            }
            return month;
        },
        getDay: function(date) {
            var day = "";
            day = date.getDate();
            if (day < 10) {
                day = "0" + day;
            }
            return day;
        }
    }
}
</script>

